import{_ as e,o as a,c as t,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"DeerFlow Tool System","description":"","frontmatter":{"title":"DeerFlow Tool System","status":"complete"},"headers":[],"relativePath":"research/agents/deer-flow/tool-system.md","filePath":"research/agents/deer-flow/tool-system.md"}'),o={name:"research/agents/deer-flow/tool-system.md"};function l(r,s,c,i,p,d){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="deerflow-tool-system" tabindex="-1">DeerFlow Tool System <a class="header-anchor" href="#deerflow-tool-system" aria-label="Permalink to &quot;DeerFlow Tool System&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>DeerFlow&#39;s tool system is organized around two complementary concepts:</p><ol><li><strong>Skills</strong> — Markdown files (<code>.md</code>) that define high-level workflows, best practices, and references to supporting resources. A skill is a declarative specification that the LLM reads to understand <em>how</em> to approach a class of tasks.</li><li><strong>Tools</strong> — Python functions / MCP servers that give the agent concrete capabilities: web search, file I/O, bash execution, etc.</li></ol><p>Skills orchestrate tools. Tools do the actual work.</p><hr><h2 id="skills-capability-modules-as-markdown" tabindex="-1">Skills: Capability Modules as Markdown <a class="header-anchor" href="#skills-capability-modules-as-markdown" aria-label="Permalink to &quot;Skills: Capability Modules as Markdown&quot;">​</a></h2><h3 id="what-a-skill-is" tabindex="-1">What a Skill Is <a class="header-anchor" href="#what-a-skill-is" aria-label="Permalink to &quot;What a Skill Is&quot;">​</a></h3><p>A skill is a structured Markdown file stored at <code>/mnt/skills/public/&lt;skill-name&gt;/SKILL.md</code> (built-in) or <code>/mnt/skills/custom/&lt;skill-name&gt;/SKILL.md</code> (user-defined).</p><p>Example structure of a skill file:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">---</span></span>
<span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> research</span></span>
<span class="line"><span style="color:#89B4FA;">version</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 1.0.0</span></span>
<span class="line"><span style="color:#89B4FA;">author</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> DeerFlow Team</span></span>
<span class="line"><span style="color:#9399B2;">---</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;"># Research Skill</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Purpose</span></span>
<span class="line"><span style="color:#CDD6F4;">Conduct deep, multi-source research on any topic.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Workflow</span></span>
<span class="line"><span style="color:#94E2D5;">1.</span><span style="color:#CDD6F4;"> Decompose the research question into sub-questions</span></span>
<span class="line"><span style="color:#94E2D5;">2.</span><span style="color:#CDD6F4;"> Search for each sub-question using web_search</span></span>
<span class="line"><span style="color:#94E2D5;">3.</span><span style="color:#CDD6F4;"> Fetch and read relevant pages with web_fetch</span></span>
<span class="line"><span style="color:#94E2D5;">4.</span><span style="color:#CDD6F4;"> Cross-reference sources</span></span>
<span class="line"><span style="color:#94E2D5;">5.</span><span style="color:#CDD6F4;"> Synthesize findings into a structured report</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Best Practices</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Always verify claims with at least 2 sources</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Prefer primary sources (papers, official docs) over aggregators</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Save intermediate findings to workspace/research-notes.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Tools Required</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> web_search</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> web_fetch</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> file_write</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> file_read</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Output Format</span></span>
<span class="line"><span style="color:#CDD6F4;">Produce a structured report with: Executive Summary, Findings (by section),</span></span>
<span class="line"><span style="color:#CDD6F4;">Sources (with URLs), and Confidence Assessment.</span></span></code></pre></div><h3 id="built-in-skills" tabindex="-1">Built-In Skills <a class="header-anchor" href="#built-in-skills" aria-label="Permalink to &quot;Built-In Skills&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>research</code></td><td><code>/mnt/skills/public/research/SKILL.md</code></td><td>Deep multi-source research</td></tr><tr><td><code>report-generation</code></td><td><code>/mnt/skills/public/report-generation/SKILL.md</code></td><td>Structured report writing</td></tr><tr><td><code>slide-creation</code></td><td><code>/mnt/skills/public/slide-creation/SKILL.md</code></td><td>Presentation slide decks</td></tr><tr><td><code>web-page</code></td><td><code>/mnt/skills/public/web-page/SKILL.md</code></td><td>Generate web pages</td></tr><tr><td><code>image-generation</code></td><td><code>/mnt/skills/public/image-generation/SKILL.md</code></td><td>Generate images</td></tr><tr><td><code>claude-to-deerflow</code></td><td><code>/mnt/skills/public/claude-to-deerflow/SKILL.md</code></td><td>Bridge: Claude Code → DeerFlow</td></tr></tbody></table><h3 id="progressive-skill-loading" tabindex="-1">Progressive Skill Loading <a class="header-anchor" href="#progressive-skill-loading" aria-label="Permalink to &quot;Progressive Skill Loading&quot;">​</a></h3><p>Skills load <strong>on-demand</strong> when the task needs them, not all at once at startup:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Write a research report on X&quot;</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Task classifier detects &quot;research + report&quot; intent</span></span>
<span class="line"><span>    ├── Loads: research/SKILL.md → added to context</span></span>
<span class="line"><span>    ├── Loads: report-generation/SKILL.md → added to context</span></span>
<span class="line"><span>    └── Does NOT load: slide-creation, web-page, image-generation</span></span></code></pre></div><p><strong>Why this matters:</strong></p><ul><li>Each SKILL.md can be ~1,000–5,000 tokens</li><li>Loading all skills at startup wastes context budget</li><li>Token-sensitive models (e.g., those with 32K windows) need lean contexts</li><li>Progressive loading keeps the active context focused on the current task</li></ul><h3 id="custom-skills" tabindex="-1">Custom Skills <a class="header-anchor" href="#custom-skills" aria-label="Permalink to &quot;Custom Skills&quot;">​</a></h3><p>Users can install custom skills in two ways:</p><ol><li><strong>Drop a <code>SKILL.md</code></strong> into <code>/mnt/skills/custom/&lt;name&gt;/</code></li><li><strong>Install a <code>.skill</code> archive</strong> via the Gateway API:<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>POST /api/gateway/skills/install</span></span>
<span class="line"><span>Content-Type: multipart/form-data</span></span>
<span class="line"><span>file: my-skill.skill</span></span></code></pre></div><code>.skill</code> archives support optional frontmatter: <code>version</code>, <code>author</code>, <code>compatibility</code>.</li></ol><h3 id="the-claude-to-deerflow-skill" tabindex="-1">The <code>claude-to-deerflow</code> Skill <a class="header-anchor" href="#the-claude-to-deerflow-skill" aria-label="Permalink to &quot;The \`claude-to-deerflow\` Skill&quot;">​</a></h3><p>A special skill that makes DeerFlow accessible directly from Claude Code:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">npx</span><span style="color:#A6E3A1;"> skills</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> https://github.com/bytedance/deer-flow</span><span style="color:#A6E3A1;"> --skill</span><span style="color:#A6E3A1;"> claude-to-deerflow</span></span></code></pre></div><p>Then from within a Claude Code session:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>/claude-to-deerflow research the competitive landscape for [X] and produce a report</span></span></code></pre></div><p>This creates a bidirectional bridge: Claude Code (CLI coding agent) can delegate research-heavy tasks to DeerFlow (super agent harness) without leaving the terminal.</p><hr><h2 id="core-tools" tabindex="-1">Core Tools <a class="header-anchor" href="#core-tools" aria-label="Permalink to &quot;Core Tools&quot;">​</a></h2><p>The built-in toolset available in the sandbox:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Runs In</th></tr></thead><tbody><tr><td><code>web_search</code></td><td>Web search via Tavily or InfoQuest</td><td>API call from sandbox</td></tr><tr><td><code>web_fetch</code></td><td>Fetch and parse a URL</td><td>HTTP from sandbox</td></tr><tr><td><code>bash</code></td><td>Execute shell commands</td><td>Docker container</td></tr><tr><td><code>file_read</code></td><td>Read file from workspace</td><td><code>/mnt/user-data/</code></td></tr><tr><td><code>file_write</code></td><td>Write file to workspace</td><td><code>/mnt/user-data/</code></td></tr><tr><td><code>file_list</code></td><td>List files in a directory</td><td><code>/mnt/user-data/</code></td></tr><tr><td><code>python</code></td><td>Execute Python code</td><td>Docker container</td></tr></tbody></table><h3 id="infoquest-integration" tabindex="-1">InfoQuest Integration <a class="header-anchor" href="#infoquest-integration" aria-label="Permalink to &quot;InfoQuest Integration&quot;">​</a></h3><p>DeerFlow integrates <strong>InfoQuest</strong>, BytePlus&#39;s intelligent search and crawling toolset:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># .env</span></span>
<span class="line"><span style="color:#A6E3A1;">INFOQUEST_API_KEY=your-infoquest-api-key</span></span></code></pre></div><p>InfoQuest provides more structured search results than general-purpose search APIs, particularly useful for multi-source research tasks.</p><hr><h2 id="mcp-server-support" tabindex="-1">MCP Server Support <a class="header-anchor" href="#mcp-server-support" aria-label="Permalink to &quot;MCP Server Support&quot;">​</a></h2><p>DeerFlow supports configuring external MCP servers to extend its toolset:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># config.yaml</span></span>
<span class="line"><span style="color:#89B4FA;">mcp_servers</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> my-db-server</span></span>
<span class="line"><span style="color:#89B4FA;">    use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> streamable_http</span></span>
<span class="line"><span style="color:#89B4FA;">    url</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> https://my-mcp-server.example.com/mcp</span></span>
<span class="line"><span style="color:#89B4FA;">    auth</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      type</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> client_credentials</span></span>
<span class="line"><span style="color:#89B4FA;">      token_url</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> https://auth.example.com/token</span></span>
<span class="line"><span style="color:#89B4FA;">      client_id</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> $CLIENT_ID</span></span>
<span class="line"><span style="color:#89B4FA;">      client_secret</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> $CLIENT_SECRET</span></span></code></pre></div><p><strong>OAuth flows supported</strong>: <code>client_credentials</code>, <code>refresh_token</code>.</p><p>Any tool exposed by an MCP server becomes available to DeerFlow&#39;s agents. This allows organizations to connect DeerFlow to internal databases, APIs, or custom capabilities without modifying the core harness.</p><hr><h2 id="tool-execution-safety" tabindex="-1">Tool Execution Safety <a class="header-anchor" href="#tool-execution-safety" aria-label="Permalink to &quot;Tool Execution Safety&quot;">​</a></h2><p>Tools execute inside an isolated Docker container per session:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Docker container (per task session)</span></span>
<span class="line"><span>├── Network: controlled (outbound HTTP allowed; inbound blocked)</span></span>
<span class="line"><span>├── Filesystem: mounted volumes only (/mnt/skills, /mnt/user-data)</span></span>
<span class="line"><span>├── Resources: configurable CPU/memory limits</span></span>
<span class="line"><span>└── Lifetime: created at session start, destroyed at session end</span></span></code></pre></div><p><strong>What the agent can do:</strong></p><ul><li>Run arbitrary bash commands in the container</li><li>Read/write to <code>/mnt/user-data/workspace/</code> and <code>/mnt/user-data/outputs/</code></li><li>Make outbound HTTP requests for search and fetch</li></ul><p><strong>What the agent cannot do:</strong></p><ul><li>Modify the host filesystem (only mounted volumes)</li><li>Access other sessions&#39; data</li><li>Persist state beyond the mounted <code>/mnt/user-data/</code> volume</li></ul><hr><h2 id="comparison-with-other-agents-tool-systems" tabindex="-1">Comparison with Other Agents&#39; Tool Systems <a class="header-anchor" href="#comparison-with-other-agents-tool-systems" aria-label="Permalink to &quot;Comparison with Other Agents&#39; Tool Systems&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>DeerFlow</th><th>Claude Code</th><th>Goose</th><th>Codex CLI</th></tr></thead><tbody><tr><td>Tool definition</td><td>Skills (Markdown) + Python fns</td><td>TypeScript functions</td><td>MCP servers</td><td>Rust trait impls</td></tr><tr><td>Extensibility</td><td>Custom SKILL.md + MCP</td><td>MCP servers</td><td>MCP servers (native)</td><td>Custom tools</td></tr><tr><td>Skill/workflow spec</td><td>Markdown files</td><td>No equivalent</td><td>No equivalent</td><td>No equivalent</td></tr><tr><td>Progressive loading</td><td>Yes (skills on-demand)</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Sandbox</td><td>Docker container</td><td>Host process</td><td>Host process</td><td>bubblewrap + Landlock</td></tr><tr><td>Skill format</td><td><code>.md</code> + optional <code>.skill</code> archive</td><td><code>.md</code> (CLAUDE.md, agent files)</td><td>GOOSE_INSTRUCTIONS</td><td>No equivalent</td></tr></tbody></table>`,52)])])}const m=e(o,[["render",l]]);export{u as __pageData,m as default};
